import java.util.*; import java.util.stream.*; class Employee2{ String name; int salary; Employee2(String n,int s){name=n;salary=s;} } public class Ten{ public static void main(String[] args){ List<Employee2> list=Arrays.asList(new Employee2("Ali",6000),new Employee2("Sara",4000),new Employee2("John",7000)); List<String> result=list.stream().filter(e->e.salary>5000).sorted((a,b)->a.salary-b.salary).map(e->e.name).collect(Collectors.toList()); System.out.println(result); }}